def _sha256_bytes(data: bytes) -> str:
    import hashlib
    return hashlib.sha256(data).hexdigest()


def _ensure_annotator(conn: sqlite3.Connection, annotator_id: str, name: Optional[str] = None):
    row = conn.execute("SELECT id FROM annotators WHERE id = ?", (annotator_id,)).fetchone()
    if row is None:
        conn.execute(
            "INSERT INTO annotators (id, name, created_at) VALUES (?, ?, ?)",
            (annotator_id, name, _utc_now()),
        )


def _recompute_aggregate(conn: sqlite3.Connection, image_id: str) -> Dict[str, Any]:
    rows = conn.execute(
        "SELECT label, COUNT(*) as c FROM labels WHERE image_id = ? GROUP BY label ORDER BY c DESC, label ASC",
        (image_id,),
    ).fetchall()
    if not rows:
        conn.execute(
            "INSERT INTO aggregated_labels (image_id, label, votes, tie, updated_at) VALUES (?, NULL, 0, 0, ?) "
            "ON CONFLICT(image_id) DO UPDATE SET label=excluded.label, votes=excluded.votes, tie=excluded.tie, updated_at=excluded.updated_at",
            (image_id, _utc_now()),
        )
        return {"image_id": image_id, "label": None, "votes": 0, "tie": False}

    top_count = rows[0]["c"]
    top_labels = [r["label"] for r in rows if r["c"] == top_count]
    tie = 1 if len(top_labels) > 1 else 0
    chosen = top_labels[0] if not tie else None

    conn.execute(
        "INSERT INTO aggregated_labels (image_id, label, votes, tie, updated_at) VALUES (?, ?, ?, ?, ?) "
        "ON CONFLICT(image_id) DO UPDATE SET label=excluded.label, votes=excluded.votes, tie=excluded.tie, updated_at=excluded.updated_at",
        (image_id, chosen, int(top_count), int(tie), _utc_now()),
    )
    return {"image_id": image_id, "label": chosen, "votes": int(top_count), "tie": bool(tie), "top_labels": top_labels}


