@app.post("/images", response_model=CreateImageResponse)
async def upload_image(file: UploadFile = File(...)):
    data = await file.read()
    if not data:
        raise HTTPException(status_code=400, detail="Empty file")
    image_id = str(uuid.uuid4())
    ext = os.path.splitext(file.filename or "")[1].lower()
    if ext not in [".jpg", ".jpeg", ".png", ".bmp", ".webp"]:
        ext = ".jpg"
    filename = f"{image_id}{ext}"
    path = os.path.join(IMAGES_DIR, filename)
    with open(path, "wb") as f:
        f.write(data)
    sha = _sha256_bytes(data)
    created_at = _utc_now()

    with _db_lock:
        conn = _connect()
        try:
            conn.execute(
                "INSERT INTO images (id, filename, sha256, created_at) VALUES (?, ?, ?, ?)",
                (image_id, filename, sha, created_at),
            )
            conn.execute(
                "INSERT INTO aggregated_labels (image_id, label, votes, tie, updated_at) VALUES (?, NULL, 0, 0, ?)",
                (image_id, created_at),
            )
            conn.commit()
        finally:
            conn.close()

    return CreateImageResponse(image_id=image_id, filename=filename, created_at=created_at)


