def _get_training_rows(conn: sqlite3.Connection) -> Tuple[List[Tuple[str, str]], List[str]]:
    rows = conn.execute(
        """
        SELECT i.id as image_id, i.filename, a.label as label
        FROM images i
        JOIN aggregated_labels a ON a.image_id = i.id
        WHERE a.label IS NOT NULL AND a.tie = 0
        ORDER BY i.created_at ASC
        """
    ).fetchall()
    items = [(r["filename"], r["label"]) for r in rows]
    classes = sorted(list({r["label"] for r in rows}))
    return items, classes


class LabeledImageDataset(Dataset):
    def __init__(self, items: List[Tuple[str, int]], image_dir: str, transform=None):
        self.items = items
        self.image_dir = image_dir
        self.transform = transform

    def __len__(self):
        return len(self.items)

    def __getitem__(self, idx):
        filename, y = self.items[idx]
        path = os.path.join(self.image_dir, filename)
        with open(path, "rb") as f:
            img = Image.open(io.BytesIO(f.read())).convert("RGB")
        if self.transform:
            img = self.transform(img)
        return img, y


class SimpleCNN(nn.Module):
    def __init__(self, num_classes: int):
        super().__init__()
        self.features = nn.Sequential(
            nn.Conv2d(3, 32, 3, stride=2, padding=1),
            nn.ReLU(inplace=True),
            nn.Conv2d(32, 64, 3, stride=2, padding=1),
            nn.ReLU(inplace=True),
            nn.Conv2d(64, 128, 3, stride=2, padding=1),
            nn.ReLU(inplace=True),
            nn.AdaptiveAvgPool2d((1, 1)),
        )
        self.classifier = nn.Linear(128, num_classes)

    def forward(self, x):
        x = self.features(x)
        x = x.flatten(1)
        return self.classifier(x)


def _train_job(job_id: str, epochs: int, batch_size: int, lr: float, device: str, image_size: int, min_labeled_images: int):
    global _train_state
    with _train_lock:
        _train_state.update(
            {
                "status": "running",
                "last_run_at": _utc_now(),
                "last_model_path": None,
                "last_num_images": 0,
                "last_num_classes": 0,
                "last_error": None,
                "running_job_id": job_id,
            }
        )

    try:
        with _db_lock:
            conn = _connect()
            try:
                items, classes = _get_training_rows(conn)
            finally:
                conn.close()

        if len(items) < min_labeled_images:
            raise RuntimeError(f"Not enough labeled images to train: {len(items)} < {min_labeled_images}")
        if len(classes) < 2:
            raise RuntimeError(f"Need at least 2 classes to train, got {len(classes)}")

        class_to_idx = {c: i for i, c in enumerate(classes)}
        indexed_items = [(fn, class_to_idx[label]) for fn, label in items]

        transform = transforms.Compose(
            [
                transforms.Resize((image_size, image_size)),
                transforms.ToTensor(),
            ]
        )

        ds = LabeledImageDataset(indexed_items, IMAGES_DIR, transform=transform)
        dl = DataLoader(ds, batch_size=batch_size, shuffle=True, num_workers=TRAIN_NUM_WORKERS)

        model = SimpleCNN(num_classes=len(classes)).to(device)
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(model.parameters(), lr=lr)

        model.train()
        for epoch in range(epochs):
            for xb, yb in dl:
                xb = xb.to(device)
                yb = yb.to(device)
                optimizer.zero_grad(set_to_none=True)
                logits = model(xb)
                loss = criterion(logits, yb)
                loss.backward()
                optimizer.step()

        ts = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
        model_path = os.path.join(MODEL_DIR, f"model_{ts}_{job_id}.pt")
        meta = {
            "job_id": job_id,
            "trained_at": _utc_now(),
            "epochs": epochs,
            "batch_size": batch_size,
            "lr": lr,
            "device": device,
            "image_size": image_size,
            "num_images": len(items),
            "classes": classes,
            "model_type": "SimpleCNN",
        }
        torch.save({"state_dict": model.state_dict(), "meta": meta}, model_path)

        with _train_lock:
            _train_state.update(
                {
                    "status": "completed",
                    "last_run_at": _utc_now(),
                    "last_model_path": model_path,
                    "last_num_images": len(items),
                    "last_num_classes": len(classes),
                    "last_error": None,
                    "running_job_id": None,
                }
            )
    except Exception as e:
        with _train_lock:
            _train_state.update(
                {
                    "status": "failed",
                    "last_run_at": _utc_now(),
                    "last_error": str(e),
                    "running_job_id": None,
                }
            )


@app.post("/train", response_model=TrainResponse)
def train(req: TrainRequest):
    epochs = int(req.epochs) if req.epochs is not None else TRAIN_EPOCHS
    batch_size = int(req.batch_size) if req.batch_size is not None else TRAIN_BATCH_SIZE
    lr = float(req.lr) if req.lr is not None else TRAIN_LR
    device = str(req.device) if req.device is not None else TRAIN_DEVICE
    image_size = int(req.image_size) if req.image_size is not None else TRAIN_IMAGE_SIZE
    min_labeled_images = int(req.min_labeled_images) if req.min_labeled_images is not None else TRAIN_MIN_LABELED_IMAGES

    if epochs < 1 or epochs > 1000:
        raise HTTPException(status_code=400, detail="Invalid epochs")
    if batch_size < 1 or batch_size > 4096:
        raise HTTPException(status_code=400, detail="Invalid batch_size")
    if lr <= 0 or lr > 1:
        raise HTTPException(status_code=400, detail="Invalid lr")

    with _train_lock:
        if _train_state["status"] == "running":
            raise HTTPException(status_code=409, detail=f"Training already running (job_id={_train_state['running_job_id']})")

    job_id = str(uuid.uuid4())
    t = threading.Thread(
        target=_train_job,
        args=(job_id, epochs, batch_size, lr, device, image_size, min_labeled_images),
        daemon=True,
    )
    t.start()
    return TrainResponse(job_id=job_id, status="started")


@app.get("/train/status", response_model=Dict[str, Any])
def train_status():
    with _train_lock:
        return dict(_train_state)


@app.get("/model/latest", response_model=Dict[str, Any])
def get_latest_model_info():
    with _train_lock:
        path = _train_state.get("last_model_path")
    if not path:
        raise HTTPException(status_code=404, detail="No trained model available")
    if not os.path.exists(path):
        raise HTTPException(status_code=404, detail="Model file missing")
    ckpt = torch.load(path, map_location="cpu")
    return {"model_path": path, "meta": ckpt.get("meta", {})}


@app.get("/model/latest/file")
def download_latest_model():
    with _train_lock:
        path = _train_state.get("last_model_path")
    if not path:
        raise HTTPException(status_code=404, detail="No trained model available")
    if not os.path.exists(path):
        raise HTTPException(status_code=404, detail="Model file missing")
    return FileResponse(path, filename=os.path.basename(path))


@app.get("/stats", response_model=Dict[str, Any])
def stats():
    with _db_lock:
        conn = _connect()
        try:
            num_images = conn.execute("SELECT COUNT(*) as c FROM images").fetchone()["c"]
            num_labels = conn.execute("SELECT COUNT(*) as c FROM labels").fetchone()["c"]
            num_annotators = conn.execute("SELECT COUNT(*) as c FROM annotators").fetchone()["c"]
            num_agg_labeled = conn.execute("SELECT COUNT(*) as c FROM aggregated_labels WHERE label IS NOT NULL AND tie = 0").fetchone()["c"]
            num_ties = conn.execute("SELECT COUNT(*) as c FROM aggregated_labels WHERE tie = 1").fetchone()["c"]
            return {
                "num_images": int(num_images),
                "num_labels": int(num_labels),
                "num_annotators": int(num_annotators),
                "num_aggregated_labeled_images": int(num_agg_labeled),
                "num_ties": int(num_ties),
            }
        finally:
            conn.close()


